VALUES
  ('heelevel3-d0d1b9a2-moex-00165', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '行政院推動功能業務與組織調整，並已陸續到位完成，其機關在年度內進行變更者，其決算辦理 方式，下列敘述何者錯誤？', '["機關改組者，由改組後之機關編造", "機關名稱更改者，由更改前、後之機關分別編造", "數機關為一機關者，在未合併以前各該機關之決算，由合併後之機關代為分別編造", "機關之改組後分立者，其未分立期間之決算，由原機關編造"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00166', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '各機關實施內部審核，應由會計人員執行之。但涉及非會計專業規定、實質或技術性事項，應由 業務主辦單位負責辦理。依會計法規定，有關內部審核之實施，下列敘述何者錯誤？', '["內部審核之實施，兼採書面審核與實地抽查方式", "會計人員為行使內部審核職權，遇必要時，得先行封鎖各項有關簿籍、憑證或其他文件", "機關主辦會計人員，對於不合法之會計程序或會計文書，應使之更正；不更正者，應拒絕之， 並報告該機關主管長官", "機關主辦會計人員，對於不合法之會計程序或會計文書，不為異議及報告時，關於不合法行為 之責任，主辦會計人員應連帶負之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00167', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '依審計法第2條第5款規定，考核財務效能為審計職權之一，試依審計法規定，審計機關考核各 機關績效之後續處理，下列敘述何者錯誤？', '["如認為有未盡職責或效能過低者，除通知其上級機關長官外，並應報告監察院", "由於制度規章缺失或設施不良者，應提出建議改善意見於各該機關", "如認為有可提升效能或增進公共利益者，應提出建議意見於各該機關或有關機關", "應供給審核以前年度預算執行之有關資料，及財務上增進效能與減少不經濟支出之建議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00168', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '審計機關對於審計上涉及特殊事項時，得採委託方式辦理，依審計法規定，其委託辦理之內容， 下列敘述何者錯誤？', '["審計機關對於審計事務，為辦理之便利，得委託其他審計機關辦理", "審計機關對於審計上涉及特殊技術及鑑定等事項，得諮詢其他機關、團體或專門技術人員", "審計機關對於審計上涉及特殊技術及鑑定等事項，得委託其他機關、團體或專門技術人員辦理", "審計機關應尊重委託其他機關、團體或專門技術人員辦理結果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00169', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '我國中央政府採五權分立制度，依憲法第 90 條及憲法增修條文第 7 條之規定，審計權與彈劾、 糾舉等權，同為監察權之一，依監察法第1條及審計法第3條規定，審計職權由審計機關行使之。 依審計法規定，有關審計機關及人員行使職權之內容，下列敘述何者錯誤？', '["審計人員為行使職權，向各機關查閱簿籍、憑證或其他文件，或檢查現金、財物時，各該主管 人員不得隱匿或拒絕", "審計人員發覺各機關人員有財務上不法之行為，且涉及刑事者，應逕行予以起訴，並報告於監 察院", "審計機關為行使職權，得派員持審計部稽察證，向有關之公私團體或個人查詢，或調閱簿籍、 憑證或其他文件，各該負責人不得隱匿或拒絕", "審計人員發覺各機關人員有財務上不法或不忠於職務上之行為，應報告該管審計機關，通知各 該機關長官處分之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00170', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '審計機關之職權包括監督預算執行、審核財務收支、審定決算、考核財務效能、稽察財務上之違 失及核定財務責任等，依審計法規定，審計機關審查決定財務責任時，有關連帶負損害賠償責任 之情況，下列敘述何者錯誤？', '["各機關經管現金、財物或其他資產，如有遺失、毀損，或因其他意外事故而致損失者，經審計 機關查明未盡善良管理人應有之注意時，該機關長官及主辦會計人員應負損害賠償之責", "審計機關審核各機關會計報告，如發現所載事項與原始憑證不符，致使公款遭受損害者，該主 辦及經辦會計人員應負損害賠償責任", "各機關主辦及經辦出納人員簽發支票，如查明有超過核准人員核准數額，應負損害賠償責任", "由數人共同經管之遺失、毀損或損失案件，不能確定其中孰為未盡善良管理人應有之注意或故 意或重大過失時，各該經管人員應連帶負損害賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00171', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '因擔保、保證或契約可能造成未來會計年度內之支出者，應於何項文書中列表說明；其對國庫有 重大影響者，並應向何機關報告？', '["決算書，行政院", "決算書，立法院", "預算書，行政院", "預算書，立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00172', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '總預算案歲入、歲出未平衡時，應如何處理？', '["由中央財政主管機關提出解決辦法", "由立法院提出解決辦法", "中央主計機關應會同中央財政主管機關提出解決辦法", "中央主計機關應會同立法院提出解決辦法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00173', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '會計制度之設計，應依會計事務之性質、業務實際情形及其將來之發展，先決定所需要之何項文 書？', '["會計明細報表", "會計憑證", "會計報告", "決算書表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00174', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ddeb88e9', 'sub-heelevel3-d0d1b9a2-03', NULL, 'single_choice', '會計科目名稱經規定後，如擬變更時，須經下列何者核定？', '["機關長官", "上級機關長官", "各該政府主計機關或其負責主計人員", "各該政府審計機關或其負責審計人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:59+00:00", "source_pdf_sha1": "decf00fa6f3c", "answer_pdf_sha1": "9c6129bcb5e5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計審計法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
